#!/usr/bin/env node
// merge-internal-matura.js
// Merges collected questions (visible session context) into the existing bank.
// Run: node scripts/merge-internal-matura.js

const fs = require('fs');
const path = require('path');

const BANK_PATH = path.join(__dirname, '..', 'data', 'matura', 'raw', 'internal-matura-bank-gymnasium-mk.json');

// ── helpers ──────────────────────────────────────────────────────────────────
const LAT = { A: 'А', B: 'Б', C: 'В', D: 'Г' };
const latinToCyrillic = (s) => (s && LAT[s]) ? LAT[s] : s;

function convertChoices(ch) {
  if (!ch) return null;
  const keys = Object.keys(ch);
  // Already Cyrillic (А/Б/В/Г)
  if (keys.some(k => LAT[k] === undefined)) return ch;
  const out = {};
  for (const k of keys) out[LAT[k]] = ch[k];
  return out;
}

const TOPIC_MAP = {
  broevi: 'Броеви', algebra: 'Алгебра', geometrija: 'Геометрија',
  trigonometrija: 'Тригонометрија', analiza: 'Анализа',
  'matrici-vektori': 'Матрици и вектори', logika: 'Логика',
};

const CI_MAP = {
  'word-problems-ages': 'gym10-c3-5',
  'rational-expressions': 'gym10-c2-3',
  'inequalities-rational': 'gym11-c4-1',
  'vieta-formulas': 'gym11-c3-2',
  'complex-numbers': 'gym12-c1-1',
  'truth-tables': 'gym13-c5-1',
  'rectangle-circumcircle': 'gym10-c4-3',
  'pyramid-volume': 'gym11-c7-1',
  cylinder: 'gym11-c7-1',
  'trig-relations': 'gym11-c1-1',
};

function fixConceptIds(arr) {
  return arr.map(id => CI_MAP[id] || id);
}

function inferDokLevel(qt, part, pts) {
  if (qt === 'mc') return 1;
  if (part === 3) return 3;
  if (pts >= 5) return 3;
  return 2;
}

function normalize(text) {
  return text.trim().toLowerCase().replace(/\s+/g, ' ').replace(/[$\\{}^_]/g, '');
}

