// ── build full question objects ───────────────────────────────────────────────
function buildQuestion(raw, number) {
  const isMC = raw.qt === 'mc';
  const choices = isMC
    ? convertChoices({ A: raw.A, B: raw.B, C: raw.C, D: raw.D })
    : null;
  const correctAnswer = isMC ? latinToCyrillic(raw.ca) : (raw.ans || null);
  const ci = fixConceptIds(raw.ci || []);
  const imageDesc = raw.img || null;

  return {
    questionNumber: number,
    part: raw.p,
    points: raw.pts,
    questionType: raw.qt,
    questionText: raw.q,
    choices,
    correctAnswer,
    topic: TOPIC_MAP[raw.ta] || raw.ta,
    topicArea: raw.ta,
    dokLevel: inferDokLevel(raw.qt, raw.p, raw.pts),
    hasImage: imageDesc !== null,
    imageUrls: [],
    imageDescription: imageDesc,
    conceptIds: ci,
    hints: [],
    aiSolution: null,
    successRatePercent: null,
  };
}

// ── main ─────────────────────────────────────────────────────────────────────
const bank = JSON.parse(fs.readFileSync(BANK_PATH, 'utf8'));
const existing = bank.questions;
const existingNorm = new Set(existing.map(q => normalize(q.questionText)));

// Remove flagged questions and apply corrections
const processed = RAW
  .filter(raw => !shouldRemove({ questionText: raw.q }))
  .map(raw => {
    const q = buildQuestion(raw, 0); // number assigned later
    return applyCorrections(q);
  });

// Deduplicate: keep only questions not already in existing bank
const uniqueNew = processed.filter(q => !existingNorm.has(normalize(q.questionText)));

// Assign questionNumbers sequentially
let nextNum = existing.length + 1;
uniqueNew.forEach(q => { q.questionNumber = nextNum++; });

// Merge
const merged = [...existing, ...uniqueNew];

// Recalculate totals
const totalPoints = merged.reduce((s, q) => s + (q.points || 0), 0);
bank.exam.questionCount = merged.length;
bank.exam.totalPoints = totalPoints;
bank.questions = merged;

// Write
fs.writeFileSync(BANK_PATH, JSON.stringify(bank, null, 2), 'utf8');

// Stats
const topicDist = {};
merged.forEach(q => { topicDist[q.topicArea] = (topicDist[q.topicArea] || 0) + 1; });
const dokDist = {};
merged.forEach(q => { dokDist[q.dokLevel] = (dokDist[q.dokLevel] || 0) + 1; });

console.log('✅ Merge complete');
console.log(`   Existing questions : ${existing.length}`);
console.log(`   Raw new collected  : ${RAW.length}`);
console.log(`   After filter+dedup : ${uniqueNew.length} new`);
console.log(`   Total merged       : ${merged.length}`);
console.log(`   Total points       : ${totalPoints}`);
console.log('\nTopic distribution:');
Object.entries(topicDist).sort((a,b)=>b[1]-a[1]).forEach(([k,v]) => console.log(`   ${k}: ${v}`));
console.log('\nDoK distribution:');
Object.entries(dokDist).sort().forEach(([k,v]) => console.log(`   DoK ${k}: ${v}`));
